  1→/**
  2→ * Basement Lab - Workout Tracker
  3→ * State management and UI logic
  4→ */
  5→
  6→const STATE_KEY = 'basement_lab_state';
  7→const LOG_KEY = 'basement_lab_log';
  8→const THEME_KEY = 'basement_lab_theme';
  9→const MODE_KEY = 'basement_lab_mode';
 10→
 11→let programData = null;
 12→let currentState = null;
 13→
 14→// Initialize app
 15→async function init() {
 16→  loadState();
 17→  initTheme();
 18→  await loadProgram();
 19→  render();
 20→  bindEvents();
 21→}
 22→
 23→// Initialize theme and mode from localStorage or system preference
 24→function initTheme() {
 25→  const savedTheme = localStorage.getItem(THEME_KEY) || 'cyberpunk';
 26→  const savedMode = localStorage.getItem(MODE_KEY) ||
 27→    (window.matchMedia('(prefers-color-scheme: light)').matches ? 'light' : 'dark');
 28→
 29→  setTheme(savedTheme);
 30→  setMode(savedMode);
 31→  updateSettingsUI();
 32→}
 33→
 34→// Set theme (cyberpunk, material, ocean, ember)
 35→function setTheme(theme) {
 36→  document.documentElement.setAttribute('data-theme', theme);
 37→  localStorage.setItem(THEME_KEY, theme);
 38→  updateSettingsUI();
 39→}
 40→
 41→// Set mode (dark, light)
 42→function setMode(mode) {
 43→  document.documentElement.setAttribute('data-mode', mode);
 44→  localStorage.setItem(MODE_KEY, mode);
 45→
 46→  // Update meta theme-color based on mode
 47→  const metaThemeColor = document.querySelector('meta[name="theme-color"]');
 48→  if (metaThemeColor) {
 49→    metaThemeColor.setAttribute('content', mode === 'light' ? '#f5f5f5' : '#0a0a0a');
 50→  }
 51→
 52→  updateSettingsUI();
 53→}
 54→
 55→// Update settings modal UI to reflect current theme/mode
 56→function updateSettingsUI() {
 57→  const currentTheme = document.documentElement.getAttribute('data-theme') || 'cyberpunk';
 58→  const currentMode = document.documentElement.getAttribute('data-mode') || 'dark';
 59→
 60→  // Update theme options
 61→  document.querySelectorAll('.theme-option').forEach(option => {
 62→    if (option.dataset.theme === currentTheme) {
 63→      option.classList.add('active');
 64→    } else {
 65→      option.classList.remove('active');
 66→    }
 67→  });
 68→
 69→  // Update mode buttons
 70→  document.querySelectorAll('.mode-btn').forEach(btn => {
 71→    if (btn.dataset.mode === currentMode) {
 72→      btn.classList.add('active');
 73→    } else {
 74→      btn.classList.remove('active');
 75→    }
 76→  });
 77→}
 78→
 79→// Open settings modal
 80→function openSettings() {
 81→  updateSettingsUI();
 82→  document.getElementById('settings-modal').classList.remove('hidden');
 83→}
 84→
 85→// Close settings modal
 86→function closeSettings() {
 87→  document.getElementById('settings-modal').classList.add('hidden');
 88→}
 89→
 90→// Load state from localStorage
 91→function loadState() {
 92→  const saved = localStorage.getItem(STATE_KEY);
 93→  if (saved) {
 94→    currentState = JSON.parse(saved);
 95→  } else {
 96→    currentState = {
 97→      globalDay: 1,
 98→      currentPhase: 'p1'
 99→    };
100→    saveState();
101→  }
102→}
103→
104→// Save state to localStorage
105→function saveState() {
106→  localStorage.setItem(STATE_KEY, JSON.stringify(currentState));
107→}
108→
109→// Load exercise log from localStorage
110→function loadLog() {
111→  const saved = localStorage.getItem(LOG_KEY);
112→  return saved ? JSON.parse(saved) : {};
113→}
114→
115→// Save exercise log to localStorage
116→function saveLog(log) {
117→  localStorage.setItem(LOG_KEY, JSON.stringify(log));
118→}
119→
120→// Load program data from JSON
121→async function loadProgram() {
122→  try {
123→    const response = await fetch('data/program.json');
124→    programData = await response.json();
125→  } catch (error) {
126→    console.error('Failed to load program:', error);
127→    document.getElementById('workout-name').textContent = 'Error loading program';
128→  }
129→}
130→
131→// Get current phase data
132→function getCurrentPhase() {
133→  if (!programData) return null;
134→  return programData.phases.find(p => p.id === currentState.currentPhase);
135→}
136→
137→// Get workout type for current day
138→function getWorkoutType() {
139→  const phase = getCurrentPhase();
140→  if (!phase || !phase.schedule_pattern) return null;
141→
142→  // Day 1 = index 0, so subtract 1
143→  const dayIndex = (currentState.globalDay - 1) % phase.schedule_pattern.length;
144→  return phase.schedule_pattern[dayIndex];
145→}
146→
147→// Get workout data for current day
148→function getTodaysWorkout() {
149→  const phase = getCurrentPhase();
150→  const workoutType = getWorkoutType();
151→
152→  if (!phase || !workoutType || workoutType === 'Rest') {
153→    return null;
154→  }
155→
156→  return phase.workouts[workoutType];
157→}
158→
159→// Render the UI
160→function render() {
161→  // Update day counter
162→  document.getElementById('current-day').textContent = currentState.globalDay;
163→
164→  const workout = getTodaysWorkout();
165→  const workoutCard = document.getElementById('workout-card');
166→  const restDay = document.getElementById('rest-day');
167→
168→  if (!workout) {
169→    // Rest day
170→    workoutCard.classList.add('hidden');
171→    restDay.classList.remove('hidden');
172→    document.getElementById('session-progress').style.display = 'none';
173→    return;
174→  }
175→
176→  document.getElementById('session-progress').style.display = '';
177→
178→  // Workout day
179→  workoutCard.classList.remove('hidden');
180→  restDay.classList.add('hidden');
181→
182→  document.getElementById('workout-name').textContent = workout.name;
183→  document.getElementById('workout-focus').textContent = workout.focus;
184→
185→  const exercisesList = document.getElementById('exercises-list');
186→  const log = loadLog();
187→
188→  exercisesList.innerHTML = workout.exercises.map((ex, index) => {
189→    const exerciseKey = `${currentState.globalDay}_${index}`;
190→    const logEntry = log[exerciseKey] || {};
191→    const currentWeight = logEntry.weight || '';
192→    const currentDifficulty = logEntry.difficulty || '';
193→    const currentNotes = logEntry.notes || '';
194→
195→    // Calculate suggested weight for weight-based exercises
196→    const suggestedWeight = ex.uses_weight
197→      ? getSuggestedWeight(ex.name, ex.starting_weight, ex.weight_increment || 5)
198→      : null;
199→    const increment = ex.weight_increment || 5;
200→
201→    // Build weight input section
202→    let weightSection = '';
203→    if (ex.uses_weight) {
204→      weightSection = `
205→        <div class="weight-input">
206→          <label>Weight:</label>
207→          <div class="weight-controls">
208→            <button class="weight-btn" data-action="decrement" data-key="${exerciseKey}" data-increment="${increment}">-</button>
209→            <input type="number"
210→                   class="weight-field"
211→                   data-exercise="${ex.name}"
212→                   data-key="${exerciseKey}"
213→                   value="${currentWeight}"
214→                   placeholder="${suggestedWeight}">
215→            <button class="weight-btn" data-action="increment" data-key="${exerciseKey}" data-increment="${increment}">+</button>
216→          </div>
217→          <span class="unit">lbs</span>
218→          <span class="suggested-hint">suggested: ${suggestedWeight}</span>
219→        </div>
220→      `;
221→    } else if (ex.uses_weight !== false) {
222→      // Legacy exercises without uses_weight defined - show basic input
223→      const lastWeight = getLastWeight(ex.name);
224→      weightSection = `
225→        <div class="weight-input">
226→          <label>Weight:</label>
227→          <input type="number"
228→                 class="weight-field"
229→                 data-exercise="${ex.name}"
230→                 data-key="${exerciseKey}"
231→                 value="${currentWeight}"
232→                 placeholder="${lastWeight || '—'}">
233→          <span class="unit">lbs</span>
234→        </div>
235→      `;
236→    }
237→
238→    // Build collapsible feedback section (difficulty + notes)
239→    const isCompleted = logEntry.completed || false;
240→    const hasCustomFeedback = currentDifficulty && currentDifficulty !== 'good' || currentNotes;
241→    const maxSets = ex.sets;
242→    const maxReps = parseReps(ex.reps);
243→    const failedSet = logEntry.failedSet || 1;
244→    const failedRep = logEntry.failedRep || 1;
245→
246→    const feedbackSection = `
247→      <div class="feedback-section${isCompleted && hasCustomFeedback ? ' expanded' : ''}">
248→        <button class="done-btn${isCompleted ? ' is-done' : ''}" data-key="${exerciseKey}" data-exercise="${ex.name}" data-index="${index}">
249→          ${isCompleted ? '\u2713 DONE' : 'DONE'}
250→        </button>
251→        <div class="feedback-content">
252→          <div class="difficulty-input">
253→            <label>How was it?</label>
254→            <div class="difficulty-buttons">
255→              <button class="difficulty-btn${currentDifficulty === 'failed' ? ' selected' : ''}" data-difficulty="failed" data-key="${exerciseKey}" data-exercise="${ex.name}" data-sets="${maxSets}" data-reps="${maxReps}">FAILED</button>
256→              <button class="difficulty-btn${currentDifficulty === 'easy' ? ' selected' : ''}" data-difficulty="easy" data-key="${exerciseKey}" data-exercise="${ex.name}">EASY</button>
257→              <button class="difficulty-btn${currentDifficulty === 'good' || !currentDifficulty ? ' selected' : ''}" data-difficulty="good" data-key="${exerciseKey}" data-exercise="${ex.name}">GOOD</button>
258→              <button class="difficulty-btn${currentDifficulty === 'hard' ? ' selected' : ''}" data-difficulty="hard" data-key="${exerciseKey}" data-exercise="${ex.name}">HARD</button>
259→            </div>
260→          </div>
261→          <div class="failed-details${currentDifficulty === 'failed' ? ' visible' : ''}" data-key="${exerciseKey}">
262→            <div class="slider-group">
263→              <label>Failed on set: <span class="slider-value">${failedSet}</span> / ${maxSets}</label>
264→              <input type="range" class="failed-set-slider" data-key="${exerciseKey}" data-exercise="${ex.name}" min="1" max="${maxSets}" value="${failedSet}">
265→            </div>
266→            <div class="slider-group">
267→              <label>Failed on rep: <span class="slider-value">${failedRep}</span> / ${maxReps}</label>
268→              <input type="range" class="failed-rep-slider" data-key="${exerciseKey}" data-exercise="${ex.name}" min="1" max="${maxReps}" value="${failedRep}">
269→            </div>
270→          </div>
271→          <div class="notes-input">
272→            <textarea class="notes-field" data-key="${exerciseKey}" data-exercise="${ex.name}" placeholder="Notes (optional)">${currentNotes}</textarea>
273→          </div>
274→        </div>
275→      </div>
276→    `;
277→
278→    return `
279→      <div class="exercise${isCompleted ? ' completed' : ''}" data-index="${index}">
280→        <div class="exercise-header">
281→          <span class="exercise-name">${ex.name}</span>
282→          ${ex.video_id ? `<button class="video-btn" data-video="${ex.video_id}" data-start="${ex.video_start || 0}">VIDEO</button>` : '<button class="video-btn" disabled>NO VIDEO</button>'}
283→        </div>
284→        <div class="exercise-details">
285→          <span><strong>${ex.sets}</strong> sets</span>
286→          <span><strong>${ex.reps}</strong> reps</span>
287→          <span><strong>${ex.rest}</strong> rest</span>
288→        </div>
289→        ${ex.note ? `<div class="exercise-note">${ex.note}</div>` : ''}
290→        ${weightSection}
291→        ${feedbackSection}
292→      </div>
293→    `;
294→  }).join('');
295→
296→  updateProgressBar();
297→}
298→
299→// Update session progress bar
300→function updateProgressBar() {
301→  const workout = getTodaysWorkout();
302→  const bar = document.getElementById('session-progress-bar');
303→  if (!workout || !bar) {
304→    if (bar) bar.style.width = '0%';
305→    return;
306→  }
307→
308→  const log = loadLog();
309→  const total = workout.exercises.length;
310→  let completed = 0;
311→
312→  workout.exercises.forEach((ex, index) => {
313→    const key = `${currentState.globalDay}_${index}`;
314→    if (log[key] && log[key].completed) {
315→      completed++;
316→    }
317→  });
318→
319→  const percent = total > 0 ? (completed / total) * 100 : 0;
320→  bar.style.width = `${percent}%`;
321→}
322→
323→// Parse reps string to extract numeric value (e.g., "10/direction" -> 10)
324→function parseReps(repsStr) {
325→  const match = String(repsStr).match(/\d+/);
326→  return match ? parseInt(match[0]) : 10;
327→}
328→
329→// Get the last recorded weight for an exercise
330→function getLastWeight(exerciseName) {
331→  const log = loadLog();
332→  let lastWeight = null;
333→  let lastDay = 0;
334→
335→  for (const key in log) {
336→    if (log[key].exercise === exerciseName && log[key].day > lastDay) {
337→      lastWeight = log[key].weight;
338→      lastDay = log[key].day;
339→    }
340→  }
341→
342→  return lastWeight;
343→}
344→
345→// Get suggested weight with weekly progression logic
346→function getSuggestedWeight(exerciseName, startingWeight, increment = 5) {
347→  const log = loadLog();
348→  const currentWeek = Math.floor((currentState.globalDay - 1) / 7) + 1;
349→
350→  // Find last logged weight for this exercise
351→  let lastEntry = null;
352→  for (const key in log) {
353→    if (log[key].exercise === exerciseName) {
354→      if (!lastEntry || log[key].timestamp > lastEntry.timestamp) {
355→        lastEntry = log[key];
356→      }
357→    }
358→  }
359→
360→  if (!lastEntry) {
361→    return startingWeight; // First time - use starting weight
362→  }
363→
364→  const lastWeek = Math.floor((lastEntry.day - 1) / 7) + 1;
365→
366→  if (currentWeek > lastWeek) {
367→    // New week - suggest progression
368→    return Math.min(lastEntry.weight + increment, 80); // Cap at 80lbs
369→  }
370→
371→  return lastEntry.weight; // Same week - same weight
372→}
373→
374→// Increment weight for an exercise
375→function incrementWeight(exerciseKey, increment = 5) {
376→  const input = document.querySelector(`input[data-key="${exerciseKey}"]`);
377→  if (!input) return;
378→
379→  let currentValue = parseFloat(input.value) || parseFloat(input.placeholder) || 5;
380→  const newValue = Math.min(currentValue + increment, 80); // Cap at 80lbs
381→  input.value = newValue;
382→
383→  // Trigger save
384→  saveWeightInput(input);
385→}
386→
387→// Decrement weight for an exercise
388→function decrementWeight(exerciseKey, increment = 5) {
389→  const input = document.querySelector(`input[data-key="${exerciseKey}"]`);
390→  if (!input) return;
391→
392→  let currentValue = parseFloat(input.value) || parseFloat(input.placeholder) || 10;
393→  const newValue = Math.max(currentValue - increment, 5); // Min 5lbs
394→  input.value = newValue;
395→
396→  // Trigger save
397→  saveWeightInput(input);
398→}
399→
400→// Bind event listeners
401→function bindEvents() {
402→  // Settings button
403→  document.getElementById('settings-btn').addEventListener('click', openSettings);
404→
405→  // Settings modal - close on backdrop click
406→  document.getElementById('settings-modal').addEventListener('click', (e) => {
407→    if (e.target.id === 'settings-modal') {
408→      closeSettings();
409→    }
410→  });
411→
412→  // Theme selection
413→  document.querySelectorAll('.theme-option').forEach(option => {
414→    option.addEventListener('click', () => {
415→      setTheme(option.dataset.theme);
416→    });
417→  });
418→
419→  // Mode toggle
420→  document.querySelectorAll('.mode-btn').forEach(btn => {
421→    btn.addEventListener('click', () => {
422→      setMode(btn.dataset.mode);
423→    });
424→  });
425→
426→  // Back button
427→  document.getElementById('back-btn').addEventListener('click', goBack);
428→
429→  // Complete & Advance button
430→  document.getElementById('complete-btn').addEventListener('click', completeWorkout);
431→
432→  // Reset button
433→  document.getElementById('reset-btn').addEventListener('click', resetProgress);
434→
435→  // Video buttons (delegated)
436→  document.getElementById('exercises-list').addEventListener('click', (e) => {
437→    if (e.target.classList.contains('video-btn') && !e.target.disabled) {
438→      openVideo(e.target.dataset.video, e.target.dataset.start);
439→    }
440→  });
441→
442→  // Close modal
443→  document.getElementById('close-modal').addEventListener('click', closeVideo);
444→  document.getElementById('video-modal').addEventListener('click', (e) => {
445→    if (e.target.id === 'video-modal') closeVideo();
446→  });
447→
448→  // Weight inputs (delegated)
449→  document.getElementById('exercises-list').addEventListener('input', (e) => {
450→    if (e.target.classList.contains('weight-field')) {
451→      saveWeightInput(e.target);
452→    }
453→  });
454→
455→  // Weight +/- buttons (delegated)
456→  document.getElementById('exercises-list').addEventListener('click', (e) => {
457→    if (e.target.classList.contains('weight-btn')) {
458→      const action = e.target.dataset.action;
459→      const key = e.target.dataset.key;
460→      const increment = parseInt(e.target.dataset.increment) || 5;
461→
462→      if (action === 'increment') {
463→        incrementWeight(key, increment);
464→      } else if (action === 'decrement') {
465→        decrementWeight(key, increment);
466→      }
467→    }
468→  });
469→
470→  // Difficulty buttons (delegated)
471→  document.getElementById('exercises-list').addEventListener('click', (e) => {
472→    if (e.target.classList.contains('difficulty-btn')) {
473→      const key = e.target.dataset.key;
474→      const difficulty = e.target.dataset.difficulty;
475→      const exercise = e.target.dataset.exercise;
476→
477→      // Update visual selection
478→      const container = e.target.closest('.difficulty-buttons');
479→      container.querySelectorAll('.difficulty-btn').forEach(btn => btn.classList.remove('selected'));
480→      e.target.classList.add('selected');
481→
482→      // Show/hide failed details
483→      const failedDetails = document.querySelector(`.failed-details[data-key="${key}"]`);
484→      if (failedDetails) {
485→        if (difficulty === 'failed') {
486→          failedDetails.classList.add('visible');
487→        } else {
488→          failedDetails.classList.remove('visible');
489→        }
490→      }
491→
492→      // Save to log
493→      saveDifficulty(key, exercise, difficulty);
494→    }
495→  });
496→
497→  // Failed sliders (delegated)
498→  document.getElementById('exercises-list').addEventListener('input', (e) => {
499→    if (e.target.classList.contains('failed-set-slider') || e.target.classList.contains('failed-rep-slider')) {
500→      const slider = e.target;
501→      const key = slider.dataset.key;
502→      const exercise = slider.dataset.exercise;
503→
504→      // Update display value
505→      const label = slider.previousElementSibling;
506→      label.querySelector('.slider-value').textContent = slider.value;
507→
508→      // Save to log
509→      saveFailedDetails(key, exercise);
510→    }
511→  });
512→
513→  // Notes field (delegated)
514→  document.getElementById('exercises-list').addEventListener('input', (e) => {
515→    if (e.target.classList.contains('notes-field')) {
516→      saveNotes(e.target);
517→    }
518→  });
519→
520→  // Done button (delegated)
521→  document.getElementById('exercises-list').addEventListener('click', (e) => {
522→    if (e.target.classList.contains('done-btn')) {
523→      const btn = e.target;
524→      const key = btn.dataset.key;
525→      const exercise = btn.dataset.exercise;
526→      const exerciseCard = btn.closest('.exercise');
527→      const section = btn.closest('.feedback-section');
528→      const log = loadLog();
529→
530→      const wasCompleted = log[key] && log[key].completed;
531→
532→      if (!wasCompleted) {
533→        // Mark as completed, expand feedback
534→        log[key] = {
535→          ...log[key],
536→          exercise: exercise,
537→          completed: true,
538→          day: currentState.globalDay,
539→          timestamp: Date.now()
540→        };
541→        btn.classList.add('is-done');
542→        btn.innerHTML = '\u2713 DONE';
543→        exerciseCard.classList.add('completed');
544→        section.classList.add('expanded');
545→      } else {
546→        // Undo completion
547→        delete log[key].completed;
548→        // If no meaningful data left, remove the entry
549→        if (!log[key].weight && !log[key].difficulty && !log[key].notes) {
550→          delete log[key];
551→        }
552→        btn.classList.remove('is-done');
553→        btn.innerHTML = 'DONE';
554→        exerciseCard.classList.remove('completed');
555→        section.classList.remove('expanded');
556→      }
557→
558→      saveLog(log);
559→      updateProgressBar();
560→    }
561→  });
562→}
563→
564→// Save weight input to log
565→function saveWeightInput(input) {
566→  const log = loadLog();
567→  const key = input.dataset.key;
568→  const weight = input.value;
569→
570→  if (weight) {
571→    // Preserve existing fields when updating weight
572→    log[key] = {
573→      ...log[key],
574→      exercise: input.dataset.exercise,
575→      weight: parseFloat(weight),
576→      day: currentState.globalDay,
577→      timestamp: Date.now()
578→    };
579→  } else if (log[key]) {
580→    // Remove weight but keep other fields if they exist
581→    delete log[key].weight;
582→    // If no meaningful data left, remove the entry
583→    if (!log[key].difficulty && !log[key].notes) {
584→      delete log[key];
585→    }
586→  }
587→
588→  saveLog(log);
589→}
590→
591→// Save difficulty to log
592→function saveDifficulty(key, exercise, difficulty) {
593→  const log = loadLog();
594→
595→  log[key] = {
596→    ...log[key],
597→    exercise: exercise,
598→    difficulty: difficulty,
599→    day: currentState.globalDay,
600→    timestamp: Date.now()
601→  };
602→
603→  // Clear failed details if not failed
604→  if (difficulty !== 'failed') {
605→    delete log[key].failedSet;
606→    delete log[key].failedRep;
607→  }
608→
609→  saveLog(log);
610→}
611→
612→// Save failed set/rep details to log
613→function saveFailedDetails(key, exercise) {
614→  const log = loadLog();
615→  const setSlider = document.querySelector(`.failed-set-slider[data-key="${key}"]`);
616→  const repSlider = document.querySelector(`.failed-rep-slider[data-key="${key}"]`);
617→
618→  log[key] = {
619→    ...log[key],
620→    exercise: exercise,
621→    failedSet: parseInt(setSlider.value),
622→    failedRep: parseInt(repSlider.value),
623→    day: currentState.globalDay,
624→    timestamp: Date.now()
625→  };
626→
627→  saveLog(log);
628→}
629→
630→// Save notes to log
631→function saveNotes(textarea) {
632→  const log = loadLog();
633→  const key = textarea.dataset.key;
634→  const notes = textarea.value.trim();
635→
636→  if (notes || log[key]) {
637→    log[key] = {
638→      ...log[key],
639→      exercise: textarea.dataset.exercise,
640→      notes: notes,
641→      day: currentState.globalDay,
642→      timestamp: Date.now()
643→    };
644→
645→    // Clean up empty notes
646→    if (!notes) {
647→      delete log[key].notes;
648→    }
649→
650→    // If no meaningful data left, remove the entry
651→    if (!log[key].weight && !log[key].difficulty && !log[key].notes) {
652→      delete log[key];
653→    }
654→  }
655→
656→  saveLog(log);
