.done-btn {
  background: transparent;
  border: 1px solid var(--accent);
  color: var(--accent);
  padding: 0.4rem 0.75rem;
  font-size: 0.85rem;
  font-family: inherit;
  border-radius: 4px;
  cursor: pointer;
  transition: all var(--transition);
  text-transform: uppercase;
  letter-spacing: 0.05em;
  font-weight: bold;
}

.done-btn:hover {
  background: var(--accent);
  color: var(--bg-primary);
}

.done-btn.is-done {
  background: var(--accent);
  color: var(--bg-primary);
}

/* =============================================
   WEIGHT INPUT
   ============================================= */
.weight-input {
  display: flex;
  align-items: center;
  gap: 0.5rem;
  margin-top: 0.75rem;
  padding-top: 0.75rem;
  border-top: 1px solid var(--border);
}

.weight-input label {
  font-size: 0.95rem;
  color: var(--text-secondary);
}

.weight-input input {
  background: var(--bg-primary);
  border: 1px solid var(--border);
  color: var(--text-primary);
  padding: 0.5rem;
  width: 80px;
  font-family: inherit;
  font-size: 1.1rem;
  border-radius: 4px;
  text-align: center;
}

.weight-input input:focus {
  outline: none;
  border-color: var(--accent);
  box-shadow: var(--glow);
}

.weight-input .unit {
  font-size: 0.95rem;
  color: var(--text-secondary);
}

/* Weight Controls (+/- buttons) */
.weight-controls {
  display: flex;
  align-items: center;
  gap: 0.5rem;
}

.weight-btn {
  width: 32px;
  height: 32px;
  border-radius: 50%;
  border: 1px solid var(--accent);
  background: transparent;
  color: var(--accent);
  font-size: 1.2rem;
  font-family: inherit;
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  transition: all var(--transition);
}

.weight-btn:hover {
  background: var(--accent);
  color: var(--bg-primary);
}

.weight-btn:active {
  transform: scale(0.95);
}

.suggested-hint {
  font-size: 0.9rem;
  color: var(--text-secondary);
  font-style: italic;
  margin-left: 0.5rem;
}

/* =============================================
   FEEDBACK SECTION
   ============================================= */
.feedback-section {
  margin-top: 0.75rem;
  padding-top: 0.75rem;
  border-top: 1px solid var(--border);
}

.feedback-toggle {
  background: transparent;
  border: 1px solid var(--border);
  color: var(--text-secondary);
  padding: 0.4rem 0.75rem;
  font-size: 0.85rem;
  font-family: inherit;
  border-radius: 4px;
  cursor: pointer;
  transition: all var(--transition);
}

.feedback-toggle:hover {
  border-color: var(--accent);
  color: var(--accent);
}

.feedback-content {
  display: none;
  margin-top: 0.75rem;
}

.feedback-section.expanded .feedback-content {
  display: block;
}

.feedback-section.expanded .feedback-toggle {
  border-color: var(--accent);
  color: var(--accent);
}

/* Difficulty Input */
.difficulty-input {
  margin-bottom: 0.75rem;
}

.difficulty-input label {
  font-size: 0.95rem;
  color: var(--text-secondary);
  display: block;
  margin-bottom: 0.5rem;
}

.difficulty-buttons {
  display: flex;
  gap: 0.5rem;
}

.difficulty-btn {
  flex: 1;
  background: transparent;
  border: 1px solid var(--border);
  color: var(--text-secondary);
  padding: 0.5rem 0.25rem;
  font-size: 0.85rem;
  font-family: inherit;
  border-radius: 4px;
  cursor: pointer;
  transition: all var(--transition);
  text-transform: uppercase;
  letter-spacing: 0.05em;
}

.difficulty-btn:hover {
  border-color: var(--text-primary);
  color: var(--text-primary);
}

.difficulty-btn[data-difficulty="failed"] {
  border-color: var(--danger);
  color: var(--danger);
  opacity: 0.7;
}

.difficulty-btn[data-difficulty="failed"]:hover,
.difficulty-btn[data-difficulty="failed"].selected {
  background: var(--danger);
  color: var(--bg-primary);
  opacity: 1;
}

.difficulty-btn[data-difficulty="easy"] {
  border-color: var(--text-secondary);
  color: var(--text-secondary);
}

.difficulty-btn[data-difficulty="easy"]:hover,
.difficulty-btn[data-difficulty="easy"].selected {
  background: var(--text-secondary);
  color: var(--bg-primary);
}

.difficulty-btn[data-difficulty="good"] {
  border-color: var(--accent);
  color: var(--accent);
}

.difficulty-btn[data-difficulty="good"]:hover,
.difficulty-btn[data-difficulty="good"].selected {
  background: var(--accent);
  color: var(--bg-primary);
}

.difficulty-btn[data-difficulty="hard"] {
  border-color: var(--warning);
  color: var(--warning);
}

.difficulty-btn[data-difficulty="hard"]:hover,
.difficulty-btn[data-difficulty="hard"].selected {
  background: var(--warning);
  color: var(--bg-primary);
}

/* Failed Details */
.failed-details {
  display: none;
  margin-top: 0.75rem;
  padding: 0.75rem;
  background: rgba(255, 68, 68, 0.1);
  border: 1px solid var(--danger);
  border-radius: 4px;
}

