  display: block;
}

.slider-group {
  margin-bottom: 0.5rem;
}

.slider-group:last-child {
  margin-bottom: 0;
}

.slider-group label {
  display: block;
  font-size: 0.9rem;
  color: var(--text-secondary);
  margin-bottom: 0.25rem;
}

.slider-value {
  color: var(--danger);
  font-weight: bold;
}

.failed-set-slider,
.failed-rep-slider {
  width: 100%;
  height: 6px;
  -webkit-appearance: none;
  appearance: none;
  background: var(--border);
  border-radius: 3px;
  outline: none;
}

.failed-set-slider::-webkit-slider-thumb,
.failed-rep-slider::-webkit-slider-thumb {
  -webkit-appearance: none;
  appearance: none;
  width: 18px;
  height: 18px;
  background: var(--danger);
  border-radius: 50%;
  cursor: pointer;
}

.failed-set-slider::-moz-range-thumb,
.failed-rep-slider::-moz-range-thumb {
  width: 18px;
  height: 18px;
  background: var(--danger);
  border-radius: 50%;
  cursor: pointer;
  border: none;
}

/* Notes Input */
.notes-input {
  margin-top: 0.75rem;
}

.notes-field {
  width: 100%;
  background: var(--bg-primary);
  border: 1px solid var(--border);
  color: var(--text-primary);
  padding: 0.5rem;
  font-family: inherit;
  font-size: 0.95rem;
  border-radius: 4px;
  resize: vertical;
  min-height: 2.5rem;
  max-height: 6rem;
}

.notes-field:focus {
  outline: none;
  border-color: var(--accent);
  box-shadow: var(--glow);
}

.notes-field::placeholder {
  color: var(--text-secondary);
  opacity: 0.6;
}

/* =============================================
   REST DAY
   ============================================= */
#rest-day {
  text-align: center;
  padding: 3rem 1rem;
}

#rest-day h2 {
  color: var(--accent);
  font-size: 2rem;
  margin-bottom: 1rem;
}

#rest-day p {
  color: var(--text-secondary);
}

/* =============================================
   FOOTER
   ============================================= */
footer {
  position: fixed;
  bottom: 0;
  left: 0;
  right: 0;
  background: var(--bg-secondary);
  padding: 1rem;
  display: flex;
  gap: 0.5rem;
  border-top: 1px solid var(--border);
  box-shadow: var(--shadow);
}

.btn-primary {
  flex: 1;
  background: var(--accent);
  color: var(--bg-primary);
  border: none;
  padding: 1rem;
  font-size: 1.1rem;
  font-weight: bold;
  font-family: inherit;
  border-radius: 6px;
  cursor: pointer;
  transition: all var(--transition);
  text-transform: uppercase;
  letter-spacing: 0.1em;
}

.btn-primary:hover {
  background: var(--accent-dim);
  box-shadow: var(--glow);
}

.btn-primary:active {
  transform: scale(0.98);
}

.btn-secondary {
  background: transparent;
  border: 1px solid var(--border);
  color: var(--text-secondary);
  padding: 1rem;
  font-size: 1rem;
  font-family: inherit;
  border-radius: 6px;
  cursor: pointer;
  transition: all var(--transition);
}

.btn-secondary:hover {
  border-color: var(--danger);
  color: var(--danger);
}

/* =============================================
   VIDEO MODAL
   ============================================= */
.modal {
  position: fixed;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  background: rgba(0, 0, 0, 0.9);
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: 200;
  padding: 1rem;
}

.modal-content {
  background: var(--bg-card);
  border: 1px solid var(--accent);
  border-radius: var(--radius);
  width: 100%;
  max-width: 640px;
  position: relative;
  box-shadow: var(--shadow);
}

.close-btn {
  position: absolute;
  top: -40px;
  right: 0;
  background: transparent;
  border: none;
  color: var(--text-primary);
  font-size: 2rem;
  cursor: pointer;
  padding: 0.5rem;
}

#video-container {
  position: relative;
  padding-bottom: 56.25%;
  height: 0;
  overflow: hidden;
}

#video-container iframe {
  position: absolute;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  border: none;
  border-radius: var(--radius);
}

/* =============================================
   SETTINGS MODAL
   ============================================= */
.settings-modal {
  position: fixed;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  background: rgba(0, 0, 0, 0.85);
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: 300;
  padding: 1rem;
}

.settings-content {
  background: var(--bg-card);
  border: 1px solid var(--accent);
  border-radius: var(--radius);
  width: 100%;
  max-width: 320px;
  padding: 1.5rem;
  box-shadow: var(--shadow);
}

.settings-title {
  font-size: 1.2rem;
  color: var(--accent);
  margin-bottom: 1.25rem;
  text-align: center;
  letter-spacing: 0.1em;
}

.theme-grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 0.75rem;
  margin-bottom: 1.25rem;
}

.theme-option {
  background: var(--bg-secondary);
  border: 2px solid var(--border);
  border-radius: 6px;
  padding: 1rem 0.5rem;
  cursor: pointer;
  text-align: center;
  transition: all var(--transition);
}

.theme-option:hover {
  border-color: var(--text-secondary);
}

.theme-option.active {
  border-color: var(--accent);
}

.theme-swatch {
  width: 32px;
  height: 32px;
  border-radius: 50%;
  margin: 0 auto 0.5rem;
  border: 2px solid var(--border);
}

.theme-option[data-theme="cyberpunk"] .theme-swatch {
  background: #00ff88;
}

.theme-option[data-theme="material"] .theme-swatch {
  background: #009688;
}

.theme-option[data-theme="ocean"] .theme-swatch {
  background: #2196f3;
}

.theme-option[data-theme="ember"] .theme-swatch {
  background: #ff7043;
}

.theme-name {
  font-size: 0.85rem;
  color: var(--text-primary);
  text-transform: capitalize;
}

.mode-toggle-section {
  border-top: 1px solid var(--border);
  padding-top: 1.25rem;
}

.mode-toggle-row {
  display: flex;
  align-items: center;
  justify-content: space-between;
}

.mode-label {
  font-size: 0.95rem;
  color: var(--text-secondary);
}

.mode-toggle {
  display: flex;
  background: var(--bg-secondary);
  border: 1px solid var(--border);
  border-radius: 20px;
  padding: 2px;
}

.mode-btn {
  background: transparent;
  border: none;
  color: var(--text-secondary);
  padding: 0.4rem 0.75rem;
  font-size: 1rem;
  cursor: pointer;
  border-radius: 16px;
  transition: all var(--transition);
}

.mode-btn.active {
  background: var(--accent);
  color: var(--bg-primary);
}

/* =============================================
   UTILITY CLASSES
   ============================================= */
.hidden {
  display: none !important;
}

/* =============================================
   SCROLLBAR
   ============================================= */
::-webkit-scrollbar {
  width: 6px;
}

::-webkit-scrollbar-track {
  background: var(--bg-primary);
}

::-webkit-scrollbar-thumb {
  background: var(--border);
  border-radius: 3px;
}

::-webkit-scrollbar-thumb:hover {
  background: var(--accent-dim);
}

