    await page.reload();

    const body = page.locator('body');
    const bgColor = await body.evaluate(el =>
      getComputedStyle(el).backgroundColor
    );

    // Should be dark (rgb values close to 0)
    expect(bgColor).toMatch(/rgb\(\s*10,\s*10,\s*10\s*\)/);
